#!/usr/bin/env python3
from pathlib import Path
from html import escape
ROOT=Path(__file__).resolve().parents[1];OUT=ROOT/'pruvodce'
ITEMS=[
('minoritska-basta','Minoritská bašta','Dělová bašta, která chránila severovýchodní nároží města a dnes ukrývá expozici Militaria.','Bašta vznikla jako součást druhého parkánového pásu v 15. století. Zdivo dosahuje místy šířky čtyř metrů a objekt umožňoval umístění až osmi těžkých palných zbraní. Spolu s přilehlým bývalým minoritským klášterem a další baštou tvořila samostatný obranný celek. Od roku 2013 zde působí Městské muzeum s expozicí vojenských dějin.','Začněte na Mírovém náměstí, projděte Katovou uličkou na parkán a pokračujte vlevo. Po návštěvě se vraťte přes hradební okruh k barbakánu.','Mohutné zdivo, střílny, napojení kláštera na hradby, výhled z parkánu a interaktivní části expozice.','Pěšky z Mírového náměstí asi 5 minut. Parkování na náměstí je placené ve všední dny; zdarma lze stát u Studentského náměstí. Otevírací doba je sezónní.','https://kadan.eu/pamatky/minoritska-basta/'),
('barbakan-zatecke-brany','Barbakán Žatecké brány','Jeden z nejstarších dochovaných barbakánů rondelového typu ve střední Evropě.','Pozdně gotický obranný prvek vznikl roku 1458 při modernizaci městského opevnění. Chránil dnes již zaniklou Žateckou bránu před přímou dělostřelbou a umožňoval obráncům boční palbu. Nad portálem je městský znak s latinským nápisem připomínajícím rok výstavby.','Projděte od Kadaňského hradu po parkánu směrem k ulici Na Příkopě. Barbakán spojte se Svatou bránou, Katovou uličkou a Minoritskou baštou.','Gotický portál, znak města, fragmenty střílen, chrliče a zakřivení rondelu.','Objekt je nejlépe viditelný z ulice Na Příkopě. Parkovat lze v centru nebo u hradu. Exteriér je volně přístupný.','https://kadan.eu/pamatky/barbakan-zatecke-brany/'),
('kostel-povyseni-svateho-krize','Kostel Povýšení svatého Kříže','Hlavní katolický chrám Kadaně, v němž se propojuje gotické jádro s barokními přestavbami.','Kostel vznikl po polovině 13. století a v pramenech se objevuje roku 1291. Poškozovaly jej husitské války i opakované požáry. Současná podoba zachovává gotické části, například předsíň s portálem a krouženou klenbou, ale nese i výraznou barokní stopu.','Začněte na Mírovém náměstí, obejděte chrám ze všech stran a pokračujte za kostel ke kapli Růžencového bratrstva a na hradební parkán.','Hlavní průčelí, gotický portál, vysoká silueta, detaily oken a vztah kostela k radniční věži.','Kostel stojí přímo na Mírovém náměstí. Interiér je přístupný při bohoslužbách, koncertech a vybraných prohlídkách.','https://kadan.eu/pamatky/kostel-povyseni-svateho-krize/'),
('sloup-nejsvetejsi-trojice','Sloup Nejsvětější Trojice','Barokní dominanta Mírového náměstí a připomínka náboženské i městské reprezentace.','Sloup patří k nejvýraznějším sochařským prvkům historického náměstí. Vznikl v době, kdy města podobnými monumenty vyjadřovala vděčnost, víru a obnovu po válečných či epidemických krizích. Důležitý je nejen jeho ikonografický program, ale i vztah k radnici, kostelu a měšťanským domům.','Prohlídku spojte s okruhem Mírového náměstí. Nejprve si sloup obejděte, poté se na něj podívejte z podloubí a z horní části náměstí.','Celek sloupu, jednotlivé sochy, podstavec, průhled k radniční věži a večerní nasvícení.','Volně přístupný po celý rok. Nejbližší parkování je přímo na náměstí.','https://kadan.eu/pamatky/'),
('alzbetinsky-klaster','Alžbětinský klášter','Barokní klášterní areál na Špitálském předměstí s kostelem svaté Rodiny.','Základní kámen byl položen 14. července 1748. Stavbu podpořila hraběnka Karolína ze Schönkirchenu a projekt vycházel z pražského kláštera alžbětinek Na Slupi. Areál později doplnil sirotčinec, škola a lékárna. Po roce 1950 se jeho využití zásadně změnilo.','Vydejte se z centra přes Studentské náměstí směrem na Špitálské předměstí. Návštěvu spojte s kostelem Stětí sv. Jana Křtitele a procházkou k Ohři.','Hlavní průčelí, dvouramenné schodiště, kostel svaté Rodiny, alianční znak donátorky a vztah areálu k předměstí.','Interiéry nejsou běžně volně přístupné. Exteriér lze pozorovat z veřejného prostoru. Parkování je možné v okolních ulicích.','https://kadan.eu/pamatky/alzbetinsky-klaster/'),
('kostel-svateho-vavrince-zelina','Kostel sv. Vavřince na Želině','Románský kostel v krajině nad Ohří a jeden z nejpůsobivějších výletních cílů u Kadaně.','Kostel patří k nejstarším sakrálním stavbám regionu. Jeho význam nespočívá jen v architektuře, ale také v poloze nad řekou a v příběhu zanikajícího venkovského osídlení. Návštěva umožňuje spojit historii s krajinou údolí Ohře.','Z Kadaně se vydejte pěšky nebo na kole podél Ohře směrem k Želině. Trasu lze prodloužit k Nechranické přehradě.','Silueta kostela v krajině, apsida, kamenné zdivo, pohledy k Ohři a okolní stráně.','Nejvhodnější je pěší nebo cyklistický přístup. Interiér bývá přístupný jen při vybraných akcích.','https://kadan.eu/pamatky/ostatni-kostely/'),
('nabrezi-maxipsa-fika','Nábřeží Maxipsa Fíka','Pěší a cyklistická promenáda pod hradem s atrakcemi, uměním a výhledy na Ohři.','Nábřeží propojuje řeku, hrad a příběh Maxipsa Fíka. Najdete zde herní prvky, ručně ovládaný přívoz Velryba, plastiky Fíka a Áji, Kadaňský orloj, skatepark i půjčovnu lodiček. Fík je s regionem spojen přes zaniklý Ahníkov, autora Rudolfa Čechuru a herce Josefa Dvořáka.','Začněte u kostela Stětí sv. Jana Křtitele, pokračujte pod hradem ke Kadaňskému stupni a vraťte se přes centrum.','Hrad nad řekou, sochy Fíka, orloj, přívoz Velryba, vodní prvky a západ slunce nad Ohří.','Promenáda je volně přístupná, vhodná pro kočárky i kola. Parkování je u hradu a na ploše P11.','https://kadan.eu/nabrezi-maxipsa-fika/'),
('mestske-muzeum-pet-objektu','Městské muzeum a jeho pět objektů','Přehled pěti památkových objektů a šesti stálých expozic Městského muzea v Kadani.','Muzeum bylo obnoveno roku 1999 mineralogickou expozicí ve františkánském klášteře. Roku 2004 přibyla expozice Život v klášteře. Dnes muzeum spravuje klášter, radniční věž, Kadaňský hrad, Minoritskou baštu a Svatou bránu. Každý objekt ukazuje jinou vrstvu historie města.','Na celodenní okruh začněte v klášteře, pokračujte přes náměstí na radniční věž, baštu, Svatou bránu a zakončete na hradě.','Porovnejte gotickou, renesanční a barokní architekturu jednotlivých objektů a fotografujte výhledy z věží.','Provoz je sezónní a jednotlivé objekty mají odlišné časy prohlídek. Aktuální rozpis vždy ověřte na webu muzea.','https://kadan.eu/informace/mestske-muzeum/'),
('galerie-josefa-lieslera','Galerie Josefa Lieslera','Galerie současného umění v přízemí historické radnice.','Galerie představuje současné české a slovenské umění, místní tvůrce i doprovodné programy. Nese jméno malíře, grafika a ilustrátora Josefa Lieslera, rodáka z Vidolic u Pětips, který získal i cenu UNESCO za nejkrásnější známku roku.','Spojte galerii s výstupem na radniční věž a prohlídkou Mírového náměstí.','Gotické podloubí, kontrast historického prostoru a současného umění, detaily aktuální výstavy.','Vstup je zdarma. Otevírací doba se mění podle sezóny. Parkování je na Mírovém nebo Studentském náměstí.','https://kadan.eu/aktivity/galerie-josefa-lieslera/'),
('galerie-pod-sirym-nebem','Galerie pod širým nebem','Venkovní výstavní prostor na Studentském náměstí.','Galerie pravidelně představuje fotografie, pohlednice, práce profesionálních autorů i dětí z místních škol. Díky umístění ve veřejném prostoru propojuje běžnou cestu městem s výstavou a mění se častěji než klasické památky.','Projít můžete od Svaté brány na Studentské náměstí a dále k Alžbětinskému klášteru.','Celek instalace, detaily panelů, lidé procházející výstavou a průhled ke Svaté bráně.','Volně přístupná nepřetržitě a zdarma. Parkování kolem Studentského náměstí je obvykle bezplatné.','https://kadan.eu/aktivity/galerie_pod-sirym-nebem/'),
('muzeum-carodejnic','Muzeum čarodějnic','Zážitková expozice v gotických a renesančních sklepích domu U Slunce.','Expozice ukazuje čarodějnice nejen jako pohádkové bytosti, ale také jako kořenářky, vědmy a nositelky lidových znalostí. Součástí je alchymistická dílna a čarodějnická školička. Prohlídka je komentovaná a trvá přibližně 45 minut.','Muzeum zařaďte mezi radniční věž a Katovu uličku. Pro děti lze pokračovat na nábřeží Maxipsa Fíka.','Vstupní dům U Slunce, sklepní klenby, alchymistické rekvizity a atmosférické detaily.','Sezónní provoz, prohlídky zpravidla každou celou hodinu. Parkování na Mírovém náměstí nebo zdarma u Studentského náměstí.','https://kadan.eu/aktivity/muzeum-carodejnic/'),
('kadan-s-detmi','Kadaň s dětmi','Celodenní rodinný program spojující řeku, hřiště, muzeum a historické centrum.','Oficiální rodinná trasa měří přibližně 3,3 kilometru. Začíná u hradu a nábřeží, pokračuje kolem lodiček, vodních atrakcí a malé vodní elektrárny, poté míří do centra k Muzeu čarodějnic a Minoritské baště.','Pro menší děti rozdělte trasu na nábřeží a centrum. V horku začněte ráno u řeky, muzeum nechte na odpoledne.','Děti u vodních prvků, přívoz Velryba, Maxipes Fík, hrad a interaktivní expozice.','Vhodné pro kočárky s výjimkou některých historických interiérů. Doporučené parkování je P11 u hradu.','https://kadan.eu/naplanovat-den/kadan-s-detmi/'),
('kadan-na-kole','Kadaň na kole','Trasy podél Ohře, k Nechranicím, Želině a do Krušných hor.','Kadaň leží na přirozeném uzlu cyklotras. Nejjednodušší rodinné úseky vedou podél Ohře, náročnější výjezdy směřují k Úhošti, Klášterci nebo do podhůří Krušných hor. Výhodou je možnost spojit sport s památkami a koupáním.','Rodinný okruh: nábřeží – Želina – návrat. Delší varianta pokračuje k Nechranické přehradě. Sportovní varianta vede směrem na Úhošť.','Kolo pod hradem, mosty přes Ohři, krajina u Želiny a výhledy na Doupovské hory.','Na nábřeží je třeba respektovat pěší provoz. Před cestou ověřte stav tras, počasí a případné uzavírky.','https://kadan.eu/aktivity/'),
('kadan-v-zime','Kadaň v zimě','Zimní program ve městě, když jsou sezonní památky zavřené.','Zima zvýrazní strukturu historického centra a hradeb. Vhodná je procházka od Mírového náměstí přes Katovu uličku, barbakán a nábřeží. Františkánský klášter mívá vybrané zimní prohlídky a v adventu tradiční výstavy. Večer lze program doplnit kulturou nebo kinem.','Mírové náměstí – Katova ulička – hradby – barbakán – hrad – nábřeží – návrat do centra.','Zasněžené střechy, nasvícená radnice, hradby bez listí a zimní Ohře.','Počítejte s kratšími otevíracími dobami a kluzkými úseky. Aktuální provoz ověřte před cestou.','https://kadan.eu/naplanovat-den/kadan-v-zime/'),
('nejlepsi-vylety-do-okoli','Nejlepší výlety do okolí Kadaně','Výběr cílů od Ohře přes Doupovské hory až po Krušné hory.','Mezi nejzajímavější cíle patří Želina, Nechranická přehrada, národní přírodní rezervace Úhošť, hrad Hasištejn, Klášterec nad Ohří, zámky v Polákách a Pětipsích a horské oblasti kolem Klínovce. Každý cíl má jinou náročnost a sezonní omezení.','Pro půlden zvolte Želinu nebo Klášterec. Na celý den Úhošť, Hasištejn nebo Nechranice. V zimě lze pokračovat na Klínovec.','Panoramata Úhoště, vodní plocha Nechranic, zřícenina Hasištejna a údolí Ohře.','Před cestou ověřte dopravu, parkování, otevírací dobu a stav turistických tras.','https://kadan.eu/'),
('kadanske-povesti-a-osobnosti','Kadaňské pověsti a osobnosti','Příběhy, které propojují radnici, kata, hodináře, umělce a zaniklé obce.','Kadaňské pověsti se vážou k psu na radniční věži, kostlivci, Katově uličce i městskému opevnění. Z osobností vyniká hodinář Mikuláš z Kadaně, malíř Josef Liesler, autor Maxipsa Fíka Rudolf Čechura a herec Josef Dvořák. Tyto příběhy pomáhají chápat město jako živé místo, ne jen soubor staveb.','Začněte u radnice, pokračujte ke Katově uličce a na nábřeží Maxipsa Fíka. Osobnosti propojte s místy, kde působily nebo které je připomínají.','Pes na věži, radniční hodiny, Katova ulička, Galerie Josefa Lieslera a sochy Maxipsa Fíka.','Trasa je volně přístupná. Pro hlubší výklad využijte infocentrum, muzeum nebo komentovanou prohlídku.','https://kadan.eu/kadansti-rodaci/')]
STYLE='''.a{max-width:880px;padding:50px 0}.a h1{font:800 50px/1.06 Georgia,serif}.a h2{font:800 31px Georgia,serif;margin-top:42px}.a p,.a li{font-size:18px}.box{background:#f3efe6;padding:24px;border-radius:16px;margin:28px 0}.links{display:flex;gap:12px;flex-wrap:wrap;margin-top:30px}'''
for slug,title,lead,history,route,photos,access,source in ITEMS:
 body=f'''<!doctype html><html lang="cs"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{escape(title)} | Naše Kadaň</title><meta name="description" content="Podrobný průvodce: {escape(lead)}"><link rel="icon" href="/favicon.svg" type="image/svg+xml"><link rel="stylesheet" href="/style.css"><style>{STYLE}</style></head><body><header><div class="wrap head"><a class="logo" href="/"><span class="logo-mark">K</span><span>NAŠE <b>KADAŇ</b></span></a><nav><a href="/pruvodce/">Průvodce</a><a href="/">Úvod</a></nav></div></header><main><article class="wrap a"><p class="tag">KOMPLETNÍ PRŮVODCE KADANÍ</p><h1>{escape(title)}</h1><p class="section-intro">{escape(lead)}</p><h2>Historie a souvislosti</h2><p>{escape(history)}</p><h2>Doporučená trasa</h2><p>{escape(route)}</p><h2>Co fotografovat a čeho si všimnout</h2><p>{escape(photos)}</p><div class="box"><h2>Praktické informace</h2><p>{escape(access)}</p><p><b>Aktuální provoz:</b> před návštěvou vždy ověřte na původním zdroji, protože otevírací doby, ceny a přístupnost se mohou měnit.</p></div><h2>Jak místo zapadá do Kadaně</h2><p>Nejlepší návštěva nevznikne odškrtnutím jediné památky. Toto místo propojte s okolními ulicemi, veřejným prostorem, řekou nebo dalšími objekty uvedenými v našem průvodci. Právě souvislosti ukazují, jak se Kadaň vyvíjela od královského města přes průmyslové období až po dnešní kulturní a turistické centrum.</p><div class="links"><a class="btn" href="{escape(source)}" target="_blank" rel="noopener">Ověřit aktuální informace</a><a class="btn" href="/pruvodce/">Zpět na celý průvodce</a></div></article></main><footer><div class="wrap">© 2026 Naše Kadaň · info@nasekadan.cz</div></footer></body></html>'''
 (OUT/f'{slug}.html').write_text(body,encoding='utf-8')
print(f'Vygenerováno {len(ITEMS)} průvodců.')
